          <th className="border p-2">Status</th>
          <th className="border p-2">Total</th>
        </tr>
      </thead>
      <tbody>
        {orders.map((order) => (
          <tr key={order.id}>
            <td className="border p-2">{order.id}</td>
            <td className="border p-2">{order.status}</td>
            <td className="border p-2">${order.total}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
